// Triangle Flock — hot pink / electric blue
speed = 0.6

// ---- audio (smoothed envelopes) ----
AUDIO.bins = 6; AUDIO.smooth = 0.78; AUDIO.gain = 50; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

const rampMask = () => Math.min(1, time * 0.8);

// ---- flock params ----
const DEPTH = 4;
const COLS = 12;
const ROWS = 6;
const EDGE = 0.012;
const ROUND = 0.003;
const FLOW = 0.15;

// triangle bird
const bird = () => shape(3, EDGE, ROUND);

// hot pink / electric blue palette
function birdColor(i, d) {
  const phase = i * 0.25 + time * 0.04;
  const pinkBlend = 0.5 + 0.5 * Math.sin(phase);
  const mix = d * 0.6 + (1 - pinkBlend) * 0.4;
  const r = 1.0 * (1 - mix) + 0.15 * mix + low() * 0.04;
  const g = 0.12 * (1 - mix) + 0.35 * mix + mid() * 0.02;
  const b = 0.55 * (1 - mix) + 1.0 * mix + high() * 0.03;
  return [r, g, b];
}

// flow fields — faster than original
const flowX = (i, d) => Math.sin(time * 0.18 + i * 0.8) * FLOW * (1 - d * 0.5);
const flowY = (i, d) => Math.cos(time * 0.15 + i * 0.9) * FLOW * 0.7 * (1 - d * 0.5);

function flockLayer(i) {
  const d = i / (DEPTH - 1);
  const cols = Math.max(6, Math.floor(COLS - i * 1.5));
  const rows = Math.max(3, Math.floor(ROWS - i));

  let layer = bird()
    .repeat(cols, rows)
    .scale(() => 0.6 - d * 0.12 + Math.sin(time * 0.6 + i) * 0.02 + amp() * 0.015)
    .rotate(() => time * 0.06 * (1 + d * 0.2) + Math.sin(time * 0.08 + i * 1.2) * 0.03)
    .scrollX(() => flowX(i, d))
    .scrollY(() => flowY(i, d))
    .modulate(
      noise(1.2 - d * 0.3, 0.03 + d * 0.04),
      0.1 + d * 0.15
    )
    .brightness(0.02 + d * 0.006);

  const colTint = () => {
    const c = birdColor(i, d);
    const gain = 0.06 + amp() * 0.01;
    return [c[0] + gain * low(), c[1] + gain * mid(), c[2] + gain * high()];
  };

  return layer.color(
    () => colTint()[0],
    () => colTint()[1],
    () => colTint()[2]
  );
}

// render 4 depth layers to buffers
flockLayer(0).out(o1);
flockLayer(1).out(o2);
flockLayer(2)
  .add(flockLayer(3), 0.4)
  .out(o3);

// composite
const baseComp = () => src(o1)
  .add(src(o2), 0.35)
  .add(src(o3), 0.45)
  .contrast(1.02)
  .saturate(() => 1.1 + low() * 0.08);

baseComp().out(o0);

// ---- chromatic aberration ----
const aberr = () => src(o0)
  .r()
  .scrollX(() => 0.0025 + low() * 0.0015)
  .scrollY(() => 0.001 + mid() * 0.0008)
  .color(1.1, 0.1, 0.05)
  .add(
    src(o0).g()
    .scrollX(() => -(0.0018 + low() * 0.001))
    .scrollY(() => -(0.0009 + mid() * 0.0006))
    .color(0.15, 1.0, 0.2)
  )
  .add(
    src(o0).b()
    .scrollY(() => 0.0015 + amp() * 0.001)
    .color(0.08, 0.15, 1.1)
  )
  .saturate(() => 1.12 + mid() * 0.1)
  .colorama(() => 0.002 + amp() * 0.005);

// ---- feedback trail ----
const trail = () => src(o0)
  .blend(baseComp(), () => rampMask() * (0.52 + amp() * 0.14))
  .modulateScale(noise(1.8, 0.025), () => 0.003 + amp() * 0.001)
  .modulateRotate(noise(0.3, 0.015), 0.002)
  .luma(0.005, 0.07)
  .brightness(0.025);

// final composite
aberr()
  .blend(trail(), 0.68)
  .contrast(1.035)
  .saturate(() => 1.55 + low() * 0.12)
  .out();
